-- =========================================================
-- Frontend Primary Skill Preview Seed v3 Focused
-- =========================================================
-- v3 review: split broad/mixed modules so each module stays around 3-6 lessons where possible.
-- CSS Basics no longer contains Tailwind, CSS Architecture, or Component System content.
-- SEO is a separate module, not bundled into HTML Basics.

BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_frontend_preview_skill;
CREATE TEMP TABLE seed_frontend_preview_skill (slug text PRIMARY KEY, name text NOT NULL, category text NOT NULL, description text NOT NULL) ON COMMIT DROP;
SELECT name, slug, category, description, true, now(), now() FROM seed_frontend_preview_skill
ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, category = EXCLUDED.category, description = EXCLUDED.description, is_active = true, updated_at = now();

DROP TABLE IF EXISTS seed_frontend_primary_node_skill;
CREATE TEMP TABLE seed_frontend_primary_node_skill (node_key text PRIMARY KEY, skill_slug text NOT NULL, node_title text NOT NULL, previous_primary_skill text NOT NULL, note text NOT NULL) ON COMMIT DROP;

DO $$
DECLARE missing_nodes text; missing_skills text;
BEGIN
    SELECT string_agg(p.node_key, ', ' ORDER BY p.node_key) INTO missing_nodes
    FROM seed_frontend_primary_node_skill p
    WHERE NOT EXISTS (
        SELECT 1 FROM public.roadmap_node rn
        JOIN public.roadmap_version rv ON rv.roadmap_version_id = rn.roadmap_version_id
        JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
        WHERE r.slug = 'frontend-developer-roadmap' AND rn.slug = p.node_key
    );
    IF missing_nodes IS NOT NULL THEN
        RAISE EXCEPTION 'Missing frontend roadmap nodes for primary skill preview v3 seed: %', missing_nodes;
    END IF;

    SELECT string_agg(p.skill_slug, ', ' ORDER BY p.skill_slug) INTO missing_skills
    FROM seed_frontend_primary_node_skill p
    WHERE NOT EXISTS (SELECT 1 FROM public.skill s WHERE s.slug = p.skill_slug);
    IF missing_skills IS NOT NULL THEN
        RAISE EXCEPTION 'Missing frontend primary skills: %', missing_skills;
    END IF;
END $$;

-- Rebuild frontend node-skill mappings to one focused primary skill per trackable frontend node.
DELETE FROM public.roadmap_node_skill rns
USING public.roadmap_node rn
JOIN public.roadmap_version rv ON rv.roadmap_version_id = rn.roadmap_version_id
JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id
JOIN seed_frontend_primary_node_skill p ON p.node_key = rn.slug
WHERE r.slug = 'frontend-developer-roadmap'
  AND rns.roadmap_node_id = rn.roadmap_node_id;

SELECT rn.roadmap_node_id, s.skill_id
FROM seed_frontend_primary_node_skill p
JOIN public.roadmap_node rn ON rn.slug = p.node_key
JOIN public.roadmap_version rv ON rv.roadmap_version_id = rn.roadmap_version_id
JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id AND r.slug = 'frontend-developer-roadmap'
JOIN public.skill s ON s.slug = p.skill_slug
ON CONFLICT (roadmap_node_id, skill_id) DO NOTHING;

-- Remove earlier generated frontend preview/coverage modules and recreate v3 modules.
DELETE FROM public.skill_module
WHERE metadata ->> 'seedVersion' IN (
    'frontend-primary-skill-preview-v3',
    'frontend-primary-skill-preview-v2',
    'frontend-primary-skill-preview-v1',
    'frontend-current-skill-coverage-v1',
    'frontend-roadmap-grouped-v1',
    'frontend-roadmap-coverage-v1',
    'frontend-roadmap-full-v1',
    'frontend-roadmap-full-v2'
)
OR slug IN ('accessibility-basics', 'advanced-web-platform-apis', 'browser-javascript-apis', 'browser-platform-apis', 'css-architecture', 'css-basics', 'frontend-auth-security', 'frontend-build-tooling-module', 'frontend-bundlers-code-quality', 'frontend-capstone-work', 'frontend-component-systems', 'frontend-deployment', 'frontend-e2e-testing', 'frontend-framework-core', 'frontend-framework-ecosystem', 'frontend-framework-projects', 'frontend-frameworks', 'frontend-package-management-module', 'frontend-performance', 'frontend-performance-measurement', 'frontend-performance-optimization', 'frontend-platform-apps', 'frontend-portfolio-review', 'frontend-project-deliverables', 'frontend-project-foundations', 'frontend-project-work', 'frontend-rendering', 'frontend-rendering-concepts', 'frontend-security-fundamentals', 'frontend-testing', 'frontend-testing-fundamentals', 'frontend-web-platform', 'frontend-web-security', 'git-workflow', 'graphql-client-data', 'html-basics', 'http-and-browser-networking', 'internet-fundamentals', 'javascript-basics', 'seo-basics', 'static-site-generation', 'tailwind-css', 'typescript-vite-tooling');






DO $$
DECLARE module_count int; lesson_count int; question_count int; too_large text; too_small text;
BEGIN
    SELECT COUNT(*) INTO module_count FROM public.skill_module WHERE metadata ->> 'seedVersion' = 'frontend-primary-skill-preview-v3';
    SELECT COUNT(*) INTO lesson_count FROM public.skill_module_lesson l JOIN public.skill_module m ON m.skill_module_id = l.skill_module_id WHERE m.metadata ->> 'seedVersion' = 'frontend-primary-skill-preview-v3';
    SELECT COUNT(*) INTO question_count FROM public.skill_module_quiz_question qq JOIN public.skill_module_quiz q ON q.skill_module_quiz_id = qq.skill_module_quiz_id JOIN public.skill_module m ON m.skill_module_id = q.skill_module_id WHERE m.metadata ->> 'seedVersion' = 'frontend-primary-skill-preview-v3';
    SELECT string_agg(t.title || ' (' || t.lesson_count || ')', ', ' ORDER BY t.title) INTO too_large
    FROM (
        SELECT m.title, COUNT(l.skill_module_lesson_id) AS lesson_count
        FROM public.skill_module m JOIN public.skill_module_lesson l ON l.skill_module_id = m.skill_module_id
        WHERE m.metadata ->> 'seedVersion' = 'frontend-primary-skill-preview-v3'
        GROUP BY m.skill_module_id, m.title
        HAVING COUNT(l.skill_module_lesson_id) > 6
    ) t;
    SELECT string_agg(t.title || ' (' || t.lesson_count || ')', ', ' ORDER BY t.title) INTO too_small
    FROM (
        SELECT m.title, COUNT(l.skill_module_lesson_id) AS lesson_count
        FROM public.skill_module m JOIN public.skill_module_lesson l ON l.skill_module_id = m.skill_module_id
        WHERE m.metadata ->> 'seedVersion' = 'frontend-primary-skill-preview-v3'
        GROUP BY m.skill_module_id, m.title
        HAVING COUNT(l.skill_module_lesson_id) < 3
    ) t;
    IF too_large IS NOT NULL THEN
        RAISE EXCEPTION 'v3 module lesson count too large: %', too_large;
    END IF;
    IF too_small IS NOT NULL THEN
        RAISE EXCEPTION 'v3 module lesson count too small: %', too_small;
    END IF;
    RAISE NOTICE 'Seeded frontend primary skill preview v3: % modules, % lessons, % quiz questions.', module_count, lesson_count, question_count;
END $$;
COMMIT;