INSERT INTO seed_frontend_preview_skill (slug, name, category, description) VALUES
('accessibility', 'Accessibility Basics', 'Design & UX', 'Building usable interfaces with semantic structure, keyboard support, assistive technology, contrast, and accessibility testing.'),
('advanced-web-platform-apis', 'Advanced Web Platform APIs', 'Frontend', 'Using Web Components, PWA fundamentals, service workers, realtime channels, and advanced browser platform capabilities.'),
('browser-javascript-apis', 'Browser JavaScript APIs', 'Programming', 'Using DOM APIs, Fetch/AJAX, browser storage, Shadow DOM, and browser-side behavior from JavaScript.'),
('browser-platform-apis', 'Browser Platform APIs', 'Frontend', 'Using browser compatibility checks, credentials, payments, permissions, device APIs, notifications, and location features.'),
('css', 'CSS Basics', 'Frontend', 'Core CSS foundations: cascade, box model, layout, responsive design, and media-friendly styling.'),
('css-architecture', 'CSS Architecture and Preprocessors', 'Frontend', 'Organizing CSS with BEM, CSS Modules, CSS-in-JS, Sass, PostCSS, and maintainable style boundaries.'),
('frontend-auth-security', 'Frontend Auth Security', 'Cybersecurity', 'Handling authentication UI, protected routes, JWT, OAuth, SSO, and secure auth boundaries in frontend apps.'),
('frontend-bundlers-code-quality', 'Bundlers and Code Quality', 'Tools & Workflow', 'Using ESLint, Prettier, Webpack, Rollup, Parcel, esbuild, and SWC for repeatable frontend builds.'),
('frontend-capstone-work', 'Frontend Capstone Work', 'Frontend', 'Completing capstone and offline/PWA project evidence with quality checks and roadmap-level handoff.'),
('frontend-component-systems', 'Component Systems and Design Tokens', 'Frontend', 'Building reusable component systems with design tokens, theming rules, documentation, and Storybook workflows.'),
('frontend-deployment', 'Frontend Deployment and Operations', 'DevOps & Platform', 'Deploying frontend apps with CI/CD, hosting targets, monitoring, release checks, and runtime error visibility.'),
('frontend-e2e-testing', 'Frontend End-to-End Testing', 'Software Quality', 'Testing full user flows with Cypress, Playwright, selectors, test data, CI checks, and reviewable evidence.'),
('frontend-framework-core', 'Framework Core Concepts', 'Frontend', 'Working with component composition, routing, forms, state, server state, and UI states across frontend frameworks.'),
('frontend-framework-ecosystem', 'Framework Ecosystem Choices', 'Frontend', 'Comparing React, Vue, Angular, Svelte, Solid, and Qwik so learners understand framework tradeoffs without mixing them with core concepts.'),
('frontend-framework-projects', 'Framework Dashboard Project', 'Frontend', 'Planning and completing a framework dashboard project with data flow, component boundaries, and reviewable evidence.'),
('frontend-package-management', 'Frontend Package Management', 'Tools & Workflow', 'Managing package.json, npm, Yarn, pnpm, lockfiles, scripts, dependency updates, and audit awareness.'),
('frontend-performance-measurement', 'Performance Measurement', 'Frontend', 'Measuring frontend quality with DevTools, Lighthouse, Core Web Vitals, RAIL, and quality-gate evidence.'),
('frontend-performance-optimization', 'Performance Optimization', 'Frontend', 'Improving frontend performance with bundle optimization, PRPL, storage strategy, and audit-driven fixes.'),
('frontend-platform-apps', 'Mobile and Desktop Frontend', 'Frontend', 'Exploring React Native, Flutter, Ionic, Electron, and Tauri as frontend-adjacent app platforms.'),
('frontend-portfolio-review', 'Portfolio and Review Readiness', 'Frontend', 'Polishing portfolio artifacts, final packages, review gates, and roadmap completion evidence.'),
('frontend-project-deliverables', 'Frontend Project Deliverables', 'Frontend', 'Producing concrete frontend deliverables such as landing pages, vanilla apps, forms, component slices, and workflow notes.'),
('frontend-project-foundations', 'Frontend Project Foundations', 'Frontend', 'Documenting, reviewing, debugging, internationalizing, and explaining frontend architecture decisions.'),
('frontend-rendering-concepts', 'Rendering and Hydration Concepts', 'Frontend', 'Understanding SSR, SSG, ISR, hydration, and meta-framework rendering behavior.'),
('frontend-testing-fundamentals', 'Frontend Testing Fundamentals', 'Software Quality', 'Planning unit and component tests with Jest, Vitest, Testing Library, assertions, and maintainable test structure.'),
('frontend-web-security', 'Frontend Web Security', 'Cybersecurity', 'Applying CSP, OWASP frontend risk awareness, browser security boundaries, and secure frontend review habits.'),
('git', 'Git and Repository Workflow', 'Tools & Workflow', 'Using Git and repository hosting workflows for branches, pull requests, collaboration, and frontend handoff.'),
('graphql', 'GraphQL and Client Data', 'Backend', 'Consuming GraphQL APIs with queries, fragments, cache behavior, and API-driven UI decisions.'),
('html', 'HTML Basics', 'Frontend', 'Writing clear document structure, semantic markup, forms, templates, and progressively enhanced content.'),
('http', 'HTTP and Browser Networking', 'Web', 'Using HTTP, HTTPS, CORS, certificates, request debugging, and browser networking fundamentals.'),
('internet', 'Internet Fundamentals', 'Web', 'Understanding clients, servers, DNS, hosting, browsers, and how requests move through the web.'),
('javascript', 'JavaScript Basics', 'Programming', 'Using JavaScript values, modules, functions, async work, and language foundations for frontend development.'),
('seo', 'SEO Basics', 'Frontend', 'Applying frontend SEO through metadata, semantic structure, crawlable content, links, and performance-aware pages.'),
('static-site-generation', 'Static Site Generation', 'Frontend', 'Building static portfolios and documentation sites with Astro, Eleventy, VuePress, and SSG workflows.'),
('tailwind-css', 'Tailwind CSS', 'Frontend', 'Using Tailwind utility classes, responsive variants, component extraction, and maintainable utility-first styling.'),
('typescript-vite-tooling', 'TypeScript and Vite Tooling', 'Tools & Workflow', 'Setting up TypeScript and Vite projects with typed configuration, scripts, and reviewable project templates.');
